mapper.select:
SELECT platform_id as platformId, platform_name as platformName, platform_code as platformCode, status FROM tb_platform WHERE 1=1
AND status = #{status}
ORDER BY platform_id ASC

mapper.update:
UPDATE tb_platform SET
    platform_name = #{platformName},
    platform_code = #{platformCode},
    status = #{status}
WHERE platform_id = #{platformId}
